content.text:
data "azurerm_client_config" "current" {}

data "azurerm_management_group" "root" {
  name = data.azurerm_client_config.current.tenant_id
}

locals {
  top_level_groups = {
    platform      = { display = "Platform" }
    corp          = { display = "Corp (Regulated)" }
    online        = { display = "Online" }
    sandbox       = { display = "Sandbox" }
    decommissioned = { display = "Decommissioned" }
  }
}

resource "azurerm_management_group" "top_level" {
  for_each = local.top_level_groups

  name                       = "mg-${each.key}"
  display_name               = each.value.display
  parent_management_group_id = data.azurerm_management_group.root.id
}

# Platform sub-groups
resource "azurerm_management_group" "platform_connectivity" {
  name                       = "mg-platform-connectivity"
  display_name               = "Connectivity"
  parent_management_group_id = azurerm_management_group.top_level["platform"].id
}

resource "azurerm_management_group" "platform_identity" {
  name                       = "mg-platform-identity"
  display_name               = "Identity"
  parent_management_group_id = azurerm_management_group.top_level["platform"].id
}

resource "azurerm_management_group" "platform_management" {
  name                       = "mg-platform-management"
  display_name               = "Management"
  parent_management_group_id = azurerm_management_group.top_level["platform"].id
}

targetScope = 'tenant'

param tenantId string = tenant().tenantId

// Reference the root
resource rootMg 'Microsoft.Management/managementGroups@2021-04-01' existing = {
  name: tenantId
  scope: tenant()
}

// Define the CAF top-level groups
var topLevelGroups = [
  { name: 'mg-platform', displayName: 'Platform' }
  { name: 'mg-corp', displayName: 'Corp (Regulated)' }
  { name: 'mg-online', displayName: 'Online' }
  { name: 'mg-sandbox', displayName: 'Sandbox' }
  { name: 'mg-decommissioned', displayName: 'Decommissioned' }
]

@batchSize(1)  // Create groups sequentially to avoid ARM throttling
resource topLevelMgs 'Microsoft.Management/managementGroups@2021-04-01' = [for mg in topLevelGroups: {
  name: mg.name
  scope: tenant()
  properties: {
    displayName: mg.displayName
    details: {
      parent: { id: rootMg.id }
    }
  }
}]

// Platform sub-groups (depend on platform top-level group)
resource connectivityMg 'Microsoft.Management/managementGroups@2021-04-01' = {
  name: 'mg-platform-connectivity'
  scope: tenant()
  properties: {
    displayName: 'Connectivity'
    details: {
      parent: { id: topLevelMgs[0].id }  // mg-platform is index 0
    }
  }
  dependsOn: [topLevelMgs]
}

variable "allowed_regions" {
  default = ["eastus", "eastus2", "westeurope"]
}

resource "azurerm_management_group" "corp" {
  name                       = "mg-corp"
  display_name               = "Corp (Regulated)"
  parent_management_group_id = data.azurerm_management_group.root.id
}

data "azurerm_policy_definition" "allowed_locations" {
  display_name = "Allowed locations"
}

resource "azurerm_management_group_policy_assignment" "allowed_regions_corp" {
  name                 = "allowed-regions-corp"
  display_name         = "Restrict resources to approved regions (Corp)"
  management_group_id  = azurerm_management_group.corp.id
  policy_definition_id = data.azurerm_policy_definition.allowed_locations.id

  parameters = jsonencode({
    listOfAllowedLocations = { value = var.allowed_regions }
  })
}
